"""Unit tests for the sync commands generated by sky.cloud_stores."""

import os
import stat
import subprocess
import tempfile
import unittest
from unittest import mock

from sky import cloud_stores

# The install guard must resolve `awscli_path` from PATH (falling back to
# installing awscli into the runtime venv), and the sync commands must invoke
# the resolved `$awscli_path` -- never a hardcoded venv binary. Otherwise,
# images that already ship `aws` skip the install and the sync fails with
# '.../bin/aws: No such file or directory' (#9823).
_AWSCLI_GUARD = 'awscli_path=$(which aws) || '


class TestAwsCliSyncCommands(unittest.TestCase):
    """All AWS-CLI-backed stores must invoke the binary they checked for."""

    def _check_commands(self, storage: cloud_stores.CloudStorage, source: str):
        for make_command, subcommand in (
            (storage.make_sync_dir_command, 's3 sync'),
            (storage.make_sync_file_command, 's3 cp'),
        ):
            cmd = make_command(source, '/dest')
            self.assertIn(_AWSCLI_GUARD, cmd)
            self.assertIn(f'$awscli_path {subcommand}', cmd)
            # The hardcoded venv binary may not exist when the install is
            # skipped because the image provides `aws` on PATH. (The guard's
            # install fallback may still assign the venv path to awscli_path.)
            self.assertNotIn(f'/bin/aws {subcommand}', cmd)

    def test_s3(self):
        self._check_commands(cloud_stores.S3CloudStorage(), 's3://bucket/path')

    def test_r2(self):
        with mock.patch('sky.cloud_stores.cloudflare.create_endpoint',
                        return_value='https://abc123.r2.cloudflarestorage.com'):
            self._check_commands(cloud_stores.R2CloudStorage(),
                                 'r2://bucket/path')

    def test_oci_s3(self):
        self._check_commands(cloud_stores.OciS3CloudStorage(),
                             'oci://bucket/path')

    def test_nebius(self):
        self._check_commands(cloud_stores.NebiusCloudStorage(),
                             'nebius://bucket/path')

    def test_coreweave(self):
        self._check_commands(cloud_stores.CoreWeaveCloudStorage(),
                             'cw://bucket/path')

    def test_vastdata(self):
        with mock.patch('sky.cloud_stores.vastdata.get_endpoint',
                        return_value='https://vast.example.com'):
            self._check_commands(cloud_stores.VastDataCloudStorage(),
                                 'vastdata://bucket/path')

    def test_sync_command_uses_aws_from_path(self):
        # Regression test for #9823: on an image that already provides `aws`
        # on PATH, the generated command must run that binary instead of
        # failing on a missing runtime-venv path.
        cmd = cloud_stores.CoreWeaveCloudStorage().make_sync_dir_command(
            'cw://bucket/path', '/dest')
        with tempfile.TemporaryDirectory() as stub_dir:
            stub = os.path.join(stub_dir, 'aws')
            with open(stub, 'w', encoding='utf-8') as f:
                f.write('#!/bin/sh\necho "stub-aws $@"\n')
            os.chmod(stub, os.stat(stub).st_mode | stat.S_IXUSR)
            env = dict(os.environ, PATH=f'{stub_dir}:/usr/bin:/bin')
            proc = subprocess.run(['bash', '-c', cmd],
                                  env=env,
                                  capture_output=True,
                                  text=True,
                                  check=False)
        self.assertEqual(proc.returncode, 0, proc.stderr)
        self.assertIn('stub-aws s3 sync', proc.stdout)


if __name__ == '__main__':
    unittest.main()
